'use strict';

const fs = require('node:fs');
const path = require('node:path');
const codexAdapter = require('./runtime-codex.cjs');
const { claudeToGeminiTools, convertGeminiToolName } = require('./gemini-transform.cjs');

const AUTOGENERATED_HEADER =
  '<!-- Generated by scripts/render-runtime-matrix.cjs from bin/lib/runtime-matrix.cjs. Do not hand-edit. -->';

// PHASE-9-CONSIDER: derive runtime capability rows from adapter descriptors where possible.
const CAPABILITY_REGISTRY = {
  claude: {
    statusLine: 'native',
    sessionStart: 'native',
    subagents: 'native Task() dispatch',
    sandboxEnforcement: 'permissioning system',
    hookSurface: 'settings.json hooks',
    mcp: 'native',
  },
  codex: {
    statusLine: 'unsupported',
    sessionStart: 'native',
    subagents: 'native Task() dispatch',
    sandboxEnforcement: 'per-agent .toml',
    hookSurface: 'config.toml hooks',
    mcp: 'native',
  },
  gemini: {
    statusLine: 'unsupported',
    sessionStart: 'native',
    subagents: 'subagent-as-tool',
    sandboxEnforcement: 'process sandbox',
    hookSurface: 'settings.json hooks',
    mcp: 'auto-discovered',
  },
};

const HOOK_EVENT_ROWS = [
  ['Session start', 'SessionStart', 'SessionStart', 'SessionStart'],
  ['Pre-tool', 'PreToolUse', 'PreToolUse', 'BeforeTool'],
  ['Post-tool', 'PostToolUse', 'PostToolUse', 'AfterTool'],
  ['Stop', 'Stop', 'Stop', 'SessionEnd'],
  ['Status line', 'statusLine', 'unsupported', 'unsupported'],
];

const FRONTMATTER_ROWS = [
  ['name', 'yes', 'yes', 'yes'],
  ['description', 'yes', 'yes', 'yes'],
  ['allowed-tools/tools', 'YAML array', 'comma-string', 'YAML array'],
  ['color', 'yes', 'dropped', 'dropped'],
  ['skills', 'yes', 'dropped', 'dropped'],
  ['sandbox_mode', 'n/a', 'per-agent .toml', 'n/a'],
  ['model', 'yes', 'profile-resolved .toml', 'yes'],
  ['model_reasoning_effort', 'n/a', 'profile-resolved .toml', 'n/a'],
];

const KNOWN_CLAUDE_TOOLS = [
  ...Object.keys(claudeToGeminiTools),
  'Task',
  'MultiEdit',
  'SlashCommand',
  'WebFetch',
  'WebSearch',
  'AskUserQuestion',
];

function buildCapabilityRegistry() {
  return CAPABILITY_REGISTRY;
}

function walkMarkdownFiles(dir) {
  if (!fs.existsSync(dir)) return [];
  const files = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const nextPath = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      files.push(...walkMarkdownFiles(nextPath));
    } else if (entry.isFile() && entry.name.endsWith('.md')) {
      files.push(nextPath);
    }
  }
  return files;
}

function extractFrontmatter(content) {
  const text = String(content || '');
  if (!text.startsWith('---\n')) return '';
  const endIndex = text.indexOf('\n---', 4);
  if (endIndex === -1) return '';
  return text.slice(4, endIndex);
}

function extractAllowedTools(frontmatter) {
  const tools = new Set();
  const lines = String(frontmatter || '').split(/\r?\n/);
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex += 1) {
    const line = lines[lineIndex];
    const trimmed = line.trim();
    if (!/^allowed-tools:|^tools:/i.test(trimmed)) continue;

    const inline = trimmed.replace(/^allowed-tools:\s*|^tools:\s*/i, '').trim();
    if (inline) {
      for (const item of inline.split(',')) {
        const normalized = item.trim().replace(/^['"]|['"]$/g, '');
        if (normalized) tools.add(normalized);
      }
      continue;
    }

    for (let itemIndex = lineIndex + 1; itemIndex < lines.length; itemIndex += 1) {
      const itemLine = lines[itemIndex];
      if (!/^\s+-\s+/.test(itemLine)) break;
      const normalized = itemLine.replace(/^\s+-\s+/, '').trim().replace(/^['"]|['"]$/g, '');
      if (normalized) tools.add(normalized);
      lineIndex = itemIndex;
    }
  }
  return Array.from(tools).sort();
}

function extractTaskAgents(content) {
  const agents = new Set();
  const taskCallRe = /Task\s*\(\s*subagent_type\s*=\s*['"]([^'"]+)['"]/g;
  let match;
  while ((match = taskCallRe.exec(content)) !== null) {
    agents.add(match[1]);
  }

  const xmlRe = /<task\b[^>]*\bsubagent_type=["']([^"']+)["'][^>]*>/g;
  while ((match = xmlRe.exec(content)) !== null) {
    agents.add(match[1]);
  }

  return Array.from(agents).sort();
}

function extractMentionedTools(content, frontmatterTools) {
  const tools = new Set(frontmatterTools);
  const text = String(content || '');
  for (const toolName of KNOWN_CLAUDE_TOOLS) {
    const re = new RegExp(`\\b${toolName}\\b`);
    if (re.test(text)) tools.add(toolName);
  }
  const mcpRe = /\bmcp__[A-Za-z0-9_]+__[A-Za-z0-9_]+\b/g;
  let match;
  while ((match = mcpRe.exec(text)) !== null) {
    tools.add(match[0]);
  }
  return Array.from(tools).sort();
}

function commandNameFromFile(filePath, commandsRoot) {
  const rel = path.relative(commandsRoot, filePath).replace(/\\/g, '/');
  const parts = rel.split('/');
  const baseName = parts[parts.length - 1].replace(/\.md$/, '');
  const prefix = parts.length > 1 ? parts.slice(0, -1).join('-') : 'oto';
  return `/${prefix}-${baseName}`;
}

function unsupportedOtoAgents(agents, agentSandboxes) {
  return agents.filter((agentName) => agentName.startsWith('oto-') && !agentSandboxes[agentName]);
}

function unsupportedGeminiTools(tools, toolMap) {
  return tools.filter((toolName) => {
    if (toolName.startsWith('mcp__')) return false;
    if (toolName === 'Task') return false;
    if (toolMap[toolName]) return false;
    return convertGeminiToolName(toolName) === null;
  });
}

function scanCommands(repoRoot) {
  const root = path.resolve(repoRoot || process.cwd());
  const commandsRoot = path.join(root, 'oto', 'commands');
  const agentSandboxes = codexAdapter.agentSandboxes || {};
  return walkMarkdownFiles(commandsRoot)
    .filter((filePath) => path.basename(filePath) !== 'INDEX.md')
    .map((filePath) => {
      const content = fs.readFileSync(filePath, 'utf8');
      const frontmatter = extractFrontmatter(content);
      const frontmatterTools = extractAllowedTools(frontmatter);
      const referencedAgents = extractTaskAgents(content);
      const referencedTools = extractMentionedTools(content, frontmatterTools);
      const missingCodexAgents = unsupportedOtoAgents(referencedAgents, agentSandboxes);
      const missingGeminiAgents = unsupportedOtoAgents(referencedAgents, agentSandboxes);
      const missingGeminiTools = unsupportedGeminiTools(referencedTools, claudeToGeminiTools);

      return {
        name: commandNameFromFile(filePath, commandsRoot),
        path: path.relative(root, filePath).replace(/\\/g, '/'),
        referencedAgents,
        referencedTools,
        runtimeSupport: {
          claude: true,
          codex: missingCodexAgents.length === 0,
          gemini: missingGeminiAgents.length === 0 && missingGeminiTools.length === 0,
        },
        notes: supportNotes(referencedAgents, referencedTools),
      };
    })
    .sort((a, b) => a.name.localeCompare(b.name));
}

function supportNotes(referencedAgents, referencedTools) {
  const parts = [];
  if (referencedAgents.length > 0) parts.push(`agents:${referencedAgents.length}`);
  if (referencedTools.length > 0) parts.push(`tools:${referencedTools.length}`);
  return parts.join(', ');
}

function mdCell(value) {
  return String(value ?? '')
    .replace(/\|/g, '\\|')
    .replace(/\n/g, '<br>');
}

function marker(ok) {
  return ok ? 'PASS' : 'FAIL';
}

function renderTable(headers, rows) {
  const out = [];
  out.push(`| ${headers.map(mdCell).join(' | ')} |`);
  out.push(`| ${headers.map(() => '---').join(' | ')} |`);
  for (const row of rows) {
    out.push(`| ${row.map(mdCell).join(' | ')} |`);
  }
  return out.join('\n') + '\n';
}

function renderToolNameRows(toolMap) {
  const names = Array.from(new Set([...Object.keys(toolMap), 'Task', 'mcp__*', 'MultiEdit', 'SlashCommand'])).sort();
  return names.map((name) => {
    if (name === 'Task') return [name, 'native', 'subagent-as-tool'];
    if (name === 'mcp__*') return [name, 'native', 'auto-discovered'];
    return [name, 'native', toolMap[name] || convertGeminiToolName(name) || 'filtered'];
  });
}

function renderCapabilityRows(registry) {
  return [
    ['statusLine', registry.claude.statusLine, registry.codex.statusLine, registry.gemini.statusLine],
    ['sessionStart', registry.claude.sessionStart, registry.codex.sessionStart, registry.gemini.sessionStart],
    ['Subagent dispatch', registry.claude.subagents, registry.codex.subagents, registry.gemini.subagents],
    [
      'Sandbox enforcement',
      registry.claude.sandboxEnforcement,
      registry.codex.sandboxEnforcement,
      registry.gemini.sandboxEnforcement,
    ],
    ['Hook surface', registry.claude.hookSurface, registry.codex.hookSurface, registry.gemini.hookSurface],
    ['MCP', registry.claude.mcp, registry.codex.mcp, registry.gemini.mcp],
  ];
}

function renderMatrix(ctx = {}) {
  const toolMap = ctx.claudeToGeminiTools || claudeToGeminiTools;
  const agentSandboxes = ctx.agentSandboxes || codexAdapter.agentSandboxes || {};
  const commands = (ctx.commands || scanCommands(path.join(__dirname, '..', '..')))
    .slice()
    .sort((a, b) => a.name.localeCompare(b.name));
  const version = ctx.otoVersion || 'unknown';
  const registry = buildCapabilityRegistry();

  const sandboxRows = Object.entries(agentSandboxes)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([agentName, sandboxMode]) => [agentName, sandboxMode]);

  const commandRows = commands.map((command) => [
    command.name,
    marker(command.runtimeSupport.claude),
    marker(command.runtimeSupport.codex),
    marker(command.runtimeSupport.gemini),
    command.notes || '',
  ]);

  return [
    AUTOGENERATED_HEADER,
    '',
    '# Runtime Tool Matrix',
    '',
    `_oto v${version} - generated_`,
    '',
    '## 1. Tool Name Map (Claude -> Codex -> Gemini)',
    renderTable(['Claude', 'Codex', 'Gemini'], renderToolNameRows(toolMap)),
    '## 2. Frontmatter Dialects per Runtime',
    renderTable(['Field', 'Claude', 'Codex', 'Gemini'], FRONTMATTER_ROWS),
    '## 3. Capability Gap Map (with closure mechanism)',
    renderTable(['Capability', 'Claude', 'Codex', 'Gemini'], renderCapabilityRows(registry)),
    '## 4. Hook Event Names + Sandbox Modes per Runtime',
    renderTable(['Hook', 'Claude', 'Codex', 'Gemini'], HOOK_EVENT_ROWS),
    '### Per-Agent Sandbox Modes (Codex)',
    renderTable(['Agent', 'sandbox_mode'], sandboxRows),
    '## 5. Per-Command Runtime Support Matrix (D-09)',
    renderTable(['/oto-* command', 'Claude', 'Codex', 'Gemini', 'Notes'], commandRows),
    '**Codex column at v0.1.0 close: 100% green (D-09).**',
    '**Gemini column per D-12 daily-peer bar: 100% green.**',
    '',
  ].join('\n');
}

module.exports = {
  CAPABILITY_REGISTRY,
  renderMatrix,
  scanCommands,
  buildCapabilityRegistry,
};
